messages.content:
{
  "children": [
    {
      "name": "ParseCommand",
      "purpose": "Parse the input JSON to extract command and parameters",
      "behavior": "Parse input JSON and return command type and parameters",
      "boundary": {
        "in_scope": ["JSON parsing", "command extraction"],
        "out_of_scope": ["validation", "execution"]
      },
      "semantic_inputs": [
        {"name": "input", "description": "Raw JSON input", "source": "parent input"}
      ],
      "semantic_outputs": [
        {"name": "command", "description": "Command type string", "consumer": "parent"},
        {"name": "params", "description": "Parameters for the command", "consumer": "parent"}
      ],
      "preconditions": ["input is valid JSON"],
      "postconditions": ["command and params extracted"],
      "guarantees": ["Returns command and params"],
      "composition_role": "transform",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "ValidateSendMessage",
      "purpose": "Validate send message parameters and user membership",
      "behavior": "Check that user is in channel and message is non-empty",
      "boundary": {
        "in_scope": ["user membership check", "message validation"],
        "out_of_scope": ["saving message"]
      },
      "semantic_inputs": [
        {"name": "params", "description": "Parameters including user, channel, message", "source": "parent input"},
        {"name": "channels", "description": "Channel data store", "source": "internal leaf access"}
      ],
      "semantic_outputs": [
        {"name": "valid", "description": "Boolean indicating validity", "consumer": "parent"},
        {"name": "error", "description": "Error message if invalid", "consumer": "parent"}
      ],
      "preconditions": ["params contains user, channel, message"],
      "postconditions": ["valid flag set"],
      "guarantees": ["Returns validity and optional error"],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "SaveMessage",
      "purpose": "Save a message to the messages store",
      "behavior": "Append message to channel's message list, enforce 100 limit",
      "boundary": {
        "in_scope": ["message storage", "history limit enforcement"],
        "out_of_scope": ["validation"]
      },
      "semantic_inputs": [
        {"name": "params", "description": "Parameters with user, channel, message", "source": "parent input"},
        {"name": "messages", "description": "Messages data store", "source": "internal leaf access"}
      ],
      "semantic_outputs": [
        {"name": "success", "description": "Boolean indicating save success", "consumer": "parent"}
      ],
      "preconditions": ["params validated", "messages store writable"],
      "postconditions": ["Message appended, history trimmed to 100"],
      "guarantees": ["Message saved"],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "GetHistory",
      "purpose": "Retrieve message history for a channel",
      "behavior": "Return last 100 messages from channel",
      "boundary": {
        "in_scope": ["history retrieval"],
        "out_of_scope": ["validation"]
      },
      "semantic_inputs": [
        {"name": "params", "description": "Parameters with channel", "source": "parent input"},
        {"name": "messages", "description": "Messages data store", "source": "internal leaf access"}
      ],
      "semantic_outputs": [
        {"name": "history", "description": "List of messages", "consumer": "parent"}
      ],
      "preconditions": ["channel exists"],
      "postconditions": ["History returned"],
      "guarantees": ["Returns up to 100 messages"],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "CreateChannel",
      "purpose": "Create a new channel",
      "behavior": "Add channel to channels store",
      "boundary": {
        "in_scope": ["channel creation"],
        "out_of_scope": ["validation"]
      },
      "semantic_inputs": [
        {"name": "params", "description": "Parameters with channel name", "source": "parent input"},
        {"name": "channels", "description": "Channels data store", "source": "internal leaf access"}
      ],
      "semantic_outputs": [
        {"name": "success", "description": "Boolean indicating creation success", "consumer": "parent"}
      ],
      "preconditions": ["channel name not empty", "channel does not exist"],
      "postconditions": ["Channel added to store"],
      "guarantees": ["Channel created"],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "JoinChannel",
      "purpose": "Add user to a channel",
      "behavior": "Add user to channel's member list",
      "boundary": {
        "in_scope": ["user membership"],
        "out_of_scope": ["validation"]
      },
      "semantic_inputs": [
        {"name": "params", "description": "Parameters with user and channel", "source": "parent input"},
        {"name": "channels", "description": "Channels data store", "source": "internal leaf access"}
      ],
      "semantic_outputs": [
        {"name": "success", "description": "Boolean indicating join success", "consumer": "parent"}
      ],
      "preconditions": ["channel exists", "user not already in channel"],
      "postconditions": ["User added to channel members"],
      "guarantees": ["User joined channel"],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "BuildResponse",
      "purpose": "Build the output JSON response",
      "behavior": "Construct response with success, data, message fields",
      "boundary": {
        "in_scope": ["response construction"],
        "out_of_scope": ["execution logic"]
      },
      "semantic_inputs": [
        {"name": "success", "description": "Boolean success flag", "source": "parent input"},
        {"name": "data", "description": "Data payload", "source": "parent input"},
        {"name": "message", "description": "Status message", "source": "parent input"}
      ],
      "semantic_outputs": [
        {"name": "output", "description": "JSON response object", "consumer": "parent"}
      ],
      "preconditions": ["success, data, message provided"],
      "postconditions": ["Output JSON constructed"],
      "guarantees": ["Returns valid JSON"],
      "composition_role": "aggregate",
      "stop_decompose": false,
      "stop_reason": ""
    }
  ],
  "decomposition_rationale": "The children cover all functional requirements: ParseCommand extracts the command, then based on command, parent routes to ValidateSendMessage+SaveMessage for send, GetHistory for history, CreateChannel for create, JoinChannel for join. BuildResponse constructs the final output. Each child is a self-contained function without sibling calls.",
  "orchestration_model": "conditional",
  "dataflow_sketch": [
    {"from": "parent", "to": "ParseCommand", "data": "input", "note": "parse input"},
    {"from": "ParseCommand", "to": "parent", "data": "command, params", "note": "command and params"},
    {"from": "parent", "to": "ValidateSendMessage", "data": "params, channels", "note": "if command is send"},
    {"from": "ValidateSendMessage", "to": "parent", "data": "valid, error", "note": "validation result"},
    {"from": "parent", "to": "SaveMessage", "data": "params, messages", "note": "if valid"},
    {"from": "SaveMessage", "to": "parent", "data": "success", "note": "save result"},
    {"from": "parent", "to": "GetHistory", "data": "params, messages", "note": "if command is history"},
    {"from": "GetHistory", "to": "parent", "data": "history", "note": "history data"},
    {"from": "parent", "to": "CreateChannel", "data": "params, channels", "note": "if command is create_channel"},
    {"from": "CreateChannel", "to": "parent", "data": "success", "note": "creation result"},
    {"from": "parent", "to": "JoinChannel", "data": "params, channels", "note": "if command is join"},
    {"from": "JoinChannel", "to": "parent", "data": "success", "note": "join result"},
    {"from": "parent", "to": "BuildResponse", "data": "success, data, message", "note": "build final response"},
    {"from": "BuildResponse", "to": "parent", "data": "output", "note": "final output"}
  ]
}
